import{_ as a,o,c as i,a2 as r}from"./chunks/framework.IwO0Hdn_.js";const g=JSON.parse('{"title":"[INFRASTRUCTURE] F-00.1 — Instalación y Configuración de Laravel + Livewire","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-00.1_setup_laravel_livewire.md","filePath":"backlog/F-00.1_setup_laravel_livewire.md","lastUpdated":null}'),n={name:"backlog/F-00.1_setup_laravel_livewire.md"};function c(s,e,t,l,d,p){return o(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="infrastructure-f-00-1-—-instalacion-y-configuracion-de-laravel-livewire" tabindex="-1">[INFRASTRUCTURE] F-00.1 — Instalación y Configuración de Laravel + Livewire <a class="header-anchor" href="#infrastructure-f-00-1-—-instalacion-y-configuracion-de-laravel-livewire" aria-label="Permalink to &quot;[INFRASTRUCTURE] F-00.1 — Instalación y Configuración de Laravel + Livewire&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-00 — Setup e Infraestructura Base</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>Infrastructure</code><strong>Secundaria:</strong> <code>DX / Tooling</code><strong>Impacta en:</strong> Equipo Fullstack (Laravel + Livewire)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p><strong>Punto de inicio</strong> — no tiene dependencias previas. Debe completarse antes que cualquier otro backlog.</p></blockquote><p><strong>Prioridad:</strong> <code>Must</code></p><hr><p><strong>Descripción:</strong> Como desarrollador Quiero tener el entorno Laravel 12 + Livewire 3 + Alpine.js configurado y funcionando Para que el equipo pueda empezar a desarrollar componentes sobre una base estable y validada</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Instalación Base):</strong> Dado que ejecuto <code>composer create-project laravel/laravel .</code> y <code>composer require livewire/livewire</code>, cuando el proceso termina, entonces la aplicación arranca en <code>php artisan serve</code> sin errores.</li><li>[ ] <strong>Escenario 2 (Alpine.js disponible):</strong> Dado que Livewire 3 incluye Alpine.js por defecto, cuando se carga cualquier vista Blade, entonces <code>Alpine</code> está disponible globalmente en el navegador y <code>x-data</code> / <code>x-show</code> funcionan correctamente.</li><li>[ ] <strong>Escenario 3 (.env configurado):</strong> Dado que el archivo <code>.env</code> existe, cuando se inspecciona, entonces tiene variables configuradas para: <code>DB_CONNECTION=pgsql</code>, <code>DB_HOST</code>, <code>DB_PORT=5432</code>, <code>DB_DATABASE</code>, <code>DB_USERNAME</code>, <code>DB_PASSWORD</code>, <code>APP_ENV=local</code>, <code>AUTH_EXTERNAL_URL</code>, <code>AUTH_MOCK_USER_ID=1</code>.</li><li>[ ] <strong>Escenario 4 (Vite solo para assets CSS):</strong> Dado que se usa Livewire (SSR), cuando se revisa <code>vite.config.js</code>, entonces Vite solo compila el CSS de Tailwind/App — no compila JavaScript de aplicación. Sin <code>app.js</code> de aplicación. Solo <code>resources/css/app.css</code>.</li><li>[ ] <strong>Escenario 5 (Livewire funciona):</strong> Dado que se crea un componente Livewire de prueba con un contador, cuando se renderiza en el navegador, entonces el contador se incrementa al pulsar el botón sin recargar la página.</li><li>[ ] <strong>Requisito Técnico:</strong> Dependencias Composer: <code>laravel/laravel:^12.0</code>, <code>livewire/livewire:^3.0</code>, <code>mews/purifier</code> (sanitización HTML server-side). TailwindCSS vía npm: <code>npm install -D tailwindcss @tailwindcss/vite</code>. Editor rich text vía npm: <code>npm install @tiptap/core @tiptap/starter-kit @tiptap/extension-image @tiptap/extension-link</code> (requerido por F-03.3/F-04.4/F-06.3). Crear <code>.env.example</code> con las variables necesarias. Eliminar los scaffolding innecesarios (Auth, Jetstream, Breeze si se instalaron).</li></ul><hr><p><strong>MoSCoW:</strong> <code>MUST</code><strong>Sprint:</strong> Sprint 0</p><p><strong>Notas:</strong></p><ul><li>Esta tarea es prerequisito bloqueante para TODAS las demás features.</li><li>El <code>.env</code> nunca se sube al repositorio. Solo <code>.env.example</code>.</li><li>TailwindCSS es el sistema de estilos elegido para el proyecto (mobile-first, utilidades).</li></ul>',15)])])}const v=a(n,[["render",c]]);export{g as __pageData,v as default};
